{"code": "import json
import re
import os

# Load the file containing all patents with citations
citations_file = locals()['var_functions.query_db:24']

with open(citations_file, 'r') as f:
    all_patents = json.load(f)

# Load the file containing UNIV CALIFORNIA patents
uc_file = locals()['var_functions.query_db:22']

with open(uc_file, 'r') as f:
    uc_patents_data = json.load(f)

# Step 1: Extract UNIV CALIFORNIA publication numbers
uc_pub_numbers = set()
for record in uc_patents_data:
    patents_info = record.get('Patents_info', '')
    if 'UNIV CALIFORNIA' in patents_info:
        pub_num_match = re.search(r'(?:pub\. number|publication number|has pub\. number|pub\. number is)\s+([A-Z]{2}-[^\s,\)]+)', patents_info)
        if pub_num_match:
            pub_num = pub_num_match.group(1)
            uc_pub_numbers.add(pub_num)

print(f"Step 1 - Found {len(uc_pub_numbers)} UNIV CALIFORNIA publication numbers:")
for pn in sorted(uc_pub_numbers):
    print(f"  - {pn}")

print("\n" + "="*60)

# Step 2: Find patents that cite UC patents and extract assignees
citing_assignees = {}
citation_count = 0

for record in all_patents:
    citations_str = record.get('citation', '[]')
    patents_info = record.get('Patents_info', '')

    # Skip if it's a UNIV CALIFORNIA patent
    if 'UNIV CALIFORNIA' in patents_info:
        continue

    if citations_str and citations_str != '[]':
        try:
            citations = json.loads(citations_str)
            for citation in citations:
                cited_pub_num = citation.get('publication_number')
                if cited_pub_num and cited_pub_num in uc_pub_numbers:
                    # Extract assignee from this citing patent
                    assignee_match = re.search(r'(?:owned by|assigned to|is owned by|is assigned to|holds the [A-Z]{2} patent)\s+([A-Z][^,\s\)]*(?:\s+[A-Z][^,\s\)]*)*)', patents_info)
                    if assignee_match:
                        assignee = assignee_match.group(1).strip()
                        if assignee and assignee != 'UNIV CALIFORNIA':
                            citation_count += 1
                            if assignee not in citing_assignees:
                                citing_assignees[assignee] = {
                                    'cited_uc_patents': set(),
                                    'count': 0
                                }
                            citing_assignees[assignee]['cited_uc_patents'].add(cited_pub_num)
                            citing_assignees[assignee]['count'] += 1
        except:
            continue

print(f"Step 2 - Found {len(citing_assignees)} unique assignees citing UC patents ({citation_count} total citations):")
for assignee in sorted(citing_assignees.keys()):
    count = citing_assignees[assignee]['count']
    uc_list = list(citing_assignees[assignee]['cited_uc_patents'])
    print(f"  - {assignee}: {count} citations (citing: {', '.join(uc_list[:3])}{'...' if len(uc_list) > 3 else ''})")

result = {
    'uc_patents_count': len(uc_pub_numbers),
    'citing_assignees_count': len(citing_assignees),
    'total_citations': citation_count,
    'uc_pub_numbers': list(uc_pub_numbers),
    'citing_assignees': list(citing_assignees.keys())
}

print("\n__RESULT__:")
print(json.dumps(result))"}

{"query": "SELECT pat.Patents_info, pat.citation, pat.cpc FROM publicationinfo pat WHERE EXISTS (
  SELECT 1 FROM publicationinfo uc 
  WHERE uc.Patents_info LIKE '%UNIV CALIFORNIA%' 
  AND pat.citation LIKE '%' || substr(uc.Patents_info, instr(uc.Patents_info, 'pub. number') + 13, instr(substr(uc.Patents_info, instr(uc.Patents_info, 'pub. number') + 13), '.') - 1) || '%'
) LIMIT 20", "db_name": "publication_database"}

{"code": "import json
import pandas as pd
import re
import os

# Get the file path from storage
file_path = locals()['var_functions.query_db:2']

# Check if file exists and load it
if os.path.exists(file_path):
    with open(file_path, 'r') as f:
        data = json.load(f)

    print(f"Total records loaded: {len(data)}")

    # Extract UNIV CALIFORNIA patents and their publication numbers
    uc_patents = []
    for record in data:
        patents_info = record.get('Patents_info', '')
        if 'UNIV CALIFORNIA' in patents_info:
            # Extract publication number from Patents_info
            pub_num_match = re.search(r'(?:pub\. number|publication number|has pub\. number|pub\. number is)\s+([A-Z]{2}-[^\s,]+)', patents_info)
            if pub_num_match:
                pub_num = pub_num_match.group(1)
                uc_patents.append({
                    'publication_number': pub_num,
                    'patents_info': patents_info,
                    'citation': record.get('citation', '[]')
                })

    print(f"Found {len(uc_patents)} UNIV CALIFORNIA patents")

    # Create a set of UC publication numbers for easy lookup
    uc_pub_numbers = {p['publication_number'] for p in uc_patents}
    print(f"UC publication numbers sample: {list(uc_pub_numbers)[:5]}")

    # Now find all patents that cite UC patents and get their assignees
    citing_patents = []

    for record in data:
        citations_str = record.get('citation', '[]')
        if citations_str and citations_str != '[]':
            try:
                citations = json.loads(citations_str)
                for citation in citations:
                    cited_pub_num = citation.get('publication_number')
                    if cited_pub_num and cited_pub_num in uc_pub_numbers:
                        # This patent cites a UC patent
                        patents_info = record.get('Patents_info', '')
                        if patents_info and 'UNIV CALIFORNIA' not in patents_info:
                            citing_patents.append({
                                'citing_patent_info': patents_info,
                                'cited_uc_patent': cited_pub_num,
                                'citation': citations_str
                            })
            except:
                continue

    print(f"Found {len(citing_patents)} patents that cite UC patents (excluding UC)")

    # Extract assignees from citing patents
    assignee_citations = {}
    for cp in citing_patents:
        patents_info = cp['citing_patent_info']
        # Extract assignee from patents_info
        # Pattern: "owned by ASSIGNEE" or "assigned to ASSIGNEE" or "is owned by ASSIGNEE"
        assignee_match = re.search(r'(?:owned by|assigned to|is owned by|is assigned to)\s+([A-Z][^,\s\)]*(?:\s+[A-Z][^,\s\)]*)*)', patents_info)
        if assignee_match:
            assignee = assignee_match.group(1).strip()
            if assignee != 'UNIV CALIFORNIA':
                if assignee not in assignee_citations:
                    assignee_citations[assignee] = []
                assignee_citations[assignee].append(cp['cited_uc_patent'])

    print(f"Found {len(assignee_citations)} unique assignees (excluding UNIV CALIFORNIA)")
    print(f"Assignees: {list(assignee_citations.keys())}")

    result = {
        'uc_patents_count': len(uc_patents),
        'citing_patents_count': len(citing_patents),
        'assignee_citations': assignee_citations
    }

    __RESULT__:
    print(json.dumps(result))

else:
    print(f"File not found: {file_path}")
    __RESULT__:
    print(json.dumps({'error': 'File not found'}))"}

