    'citing_assignees_count': len(citing_assignees),
    'total_citations': citation_count,
    'uc_pub_numbers': list(uc_pub_numbers),
    'citing_assignees': list(citing_assignees.keys())
}

print("\n__RESULT__:")
print(json.dumps(result))"}

