  SELECT 1 FROM publicationinfo uc 
  WHERE uc.Patents_info LIKE '%UNIV CALIFORNIA%' 
  AND pat.citation LIKE '%' || substr(uc.Patents_info, instr(uc.Patents_info, 'pub. number') + 13, instr(substr(uc.Patents_info, instr(uc.Patents_info, 'pub. number') + 13), '.') - 1) || '%'
) LIMIT 20", "db_name": "publication_database"}

